    // === Навигация ===
    nextImage() {
      if (this.currentIndex < this.images.length - 1) {
        this.currentIndex++;
        this.resetView();
        this.$nextTick(() => {
          this.fitToWindow();
        });
      }
    },
    prevImage() {
      if (this.currentIndex > 0) {
        this.currentIndex--;
        this.resetView();
        this.$nextTick(() => {
          this.fitToWindow();
        });
      }
    },
